public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  public void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  public void testSetLongSerializationPolicy_withValidPolicy_shouldSetAndReturnThis() throws Exception {
    LongSerializationPolicy policy = LongSerializationPolicy.STRING;
    GsonBuilder returned = gsonBuilder.setLongSerializationPolicy(policy);
    assertSame(gsonBuilder, returned);

    // Use reflection to verify the private field longSerializationPolicy is set correctly
    Field field = GsonBuilder.class.getDeclaredField("longSerializationPolicy");
    field.setAccessible(true);
    LongSerializationPolicy actualPolicy = (LongSerializationPolicy) field.get(gsonBuilder);
    assertSame(policy, actualPolicy);
  }

  @Test
  public void testSetLongSerializationPolicy_withNull_shouldThrowNullPointerException() {
    NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
      gsonBuilder.setLongSerializationPolicy(null);
    });
    assertEquals("serializationPolicy is marked non-null but is null", thrown.getMessage(), 
      // The exact message might differ depending on Objects.requireNonNull implementation,
      // so this assertion can be relaxed if needed.
      () -> "Expected NullPointerException message to mention null");
  }
}
